import React, { useState } from "react";
function Nominees({ nextStep, prevStep, updateData }) {
 const [nominees, setNominees] = useState([]);
 const addNominee = () => {
   setNominees([...nominees, { name: "", percentage: "" }]);
 };
 return (
<div>
<h2>Nominees</h2>
     {nominees.map((n, i) => (
<div key={i}>
<input placeholder="Name" />
<input placeholder="%" />
</div>
     ))}
<button onClick={addNominee}>Add Nominee</button>
<button onClick={prevStep}>Back</button>
<button onClick={() => { updateData({ nominees }); nextStep(); }}>Next</button>
</div>
 );
}
export default Nominees;